#include<bits/stdc++.h>
using namespace std;
int n;
long long a[20005],b[20005],t,s=-2;

int main() {
	cin>>n;
	for(int i=0; i<n; i++) {
		cin>>a[i]>>b[i];
	}
	sort(a,a+n);
	sort(b,b+n);
	for(int i=0; i<n; i++) {
		if(s==-2) {
			
			if((i+1)>=n) {
				t+=b[i]-a[i];
				break; 
			}
			if(b[i]>a[i+1]){
				s=a[i];
				continue;
			} else {
				t+=b[i]-a[i];

			}
			
		} else {
			
			if((i+1)>=n) {
				t+=b[i]-s;
				break;
			}
			if(b[i]>a[i+1]){
				continue;
			} else {
				t+=b[i]-s;
				s=-2;
			}	
		}
	}
	cout<<t;
	return 0;
}
